     1→const express = require('express');
     2→const pool = require('../lib/db');
     3→const { authMiddleware } = require('../lib/auth');
     4→const { generateInterviewQuestions, analyzeInterviewResponse, generateOverallFeedback, generateInterviewCoaching } = require('../lib/polsia-ai');
     5→const omniscoreService = require('../services/omniscore');
     6→const multer = require('multer');
     7→const fetch = require('node-fetch');
     8→const FormData = require('form-data');
     9→
    10→const router = express.Router();
    11→const upload = multer({ storage: multer.memoryStorage() });
    12→
    13→// Fallback questions if AI generation fails
    14→const FALLBACK_QUESTIONS = [
    15→  {
    16→    question: 'Tell me about yourself and why you are interested in this role.',
    17→    category: 'behavioral',
    18→    difficulty: 'easy',
    19→    key_points: ['Self-introduction', 'Relevant experience', 'Career goals', 'Enthusiasm']
    20→  },
    21→  {
    22→    question: 'Describe a challenging project you worked on. What was your role and how did you handle obstacles?',
    23→    category: 'behavioral',
    24→    difficulty: 'medium',
    25→    key_points: ['Problem-solving', 'Resilience', 'Technical skills', 'Teamwork']
    26→  },
    27→  {
    28→    question: 'How do you prioritize your work when you have multiple deadlines?',
    29→    category: 'situational',
    30→    difficulty: 'medium',
    31→    key_points: ['Time management', 'Organization', 'Communication', 'Prioritization frameworks']
    32→  },
    33→  {
    34→    question: 'Tell me about a time you received constructive criticism. How did you respond?',
    35→    category: 'behavioral',
    36→    difficulty: 'medium',
    37→    key_points: ['Self-awareness', 'Growth mindset', 'Professional maturity', 'Adaptability']
    38→  },
    39→  {
    40→    question: 'Where do you see yourself in 5 years, and how does this role fit into your career plan?',
    41→    category: 'situational',
    42→    difficulty: 'easy',
    43→    key_points: ['Career vision', 'Ambition', 'Role alignment', 'Long-term thinking']
    44→  }
    45→];
    46→
    47→// Start a new interview
    48→router.post('/start', authMiddleware, async (req, res) => {
    49→  try {
    50→    const { job_id, job_title, job_description, interview_type = 'mock' } = req.body;
    51→
    52→    // Generate questions using AI with fallback
    53→    let questions;
    54→    try {
    55→      questions = await generateInterviewQuestions(
    56→        job_title || 'Software Developer',
    57→        job_description,
    58→        5
    59→      );
    60→      console.log('AI generated', questions.length, 'interview questions');
    61→    } catch (aiErr) {
    62→      console.error('AI question generation failed, using fallback questions:', aiErr.message);
    63→      questions = FALLBACK_QUESTIONS;
    64→    }
    65→
    66→    // Validate questions array
    67→    if (!questions || !Array.isArray(questions) || questions.length === 0) {
    68→      console.warn('Invalid questions from AI, using fallback');
    69→      questions = FALLBACK_QUESTIONS;
    70→    }
    71→
    72→    // Create interview record
    73→    const result = await pool.query(
    74→      `INSERT INTO interviews (user_id, job_id, interview_type, questions, status)
    75→       VALUES ($1, $2, $3, $4, 'in_progress')
    76→       RETURNING *`,
    77→      [req.user.id, job_id, interview_type, JSON.stringify(questions)]
    78→    );
    79→
    80→    // Track mock interview start
    81→    try {
    82→      await pool.query(
    83→        'INSERT INTO events (event_type, user_id, metadata) VALUES ($1, $2, $3)',
    84→        ['mock_interview_start', req.user.id, JSON.stringify({ interview_type, job_id })]
    85→      );
    86→    } catch (e) {
    87→      console.error('Failed to log interview start event:', e);
    88→    }
    89→
    90→    res.json({
    91→      success: true,
    92→      interview: result.rows[0],
    93→      questions: questions.map((q, i) => ({
    94→        index: i,
    95→        question: q.question,
    96→        category: q.category,
    97→        difficulty: q.difficulty
    98→      }))
    99→    });
   100→  } catch (err) {
   101→    console.error('Start interview error:', err);
   102→    res.status(500).json({ error: 'Failed to start interview' });
   103→  }
   104→});
   105→
   106→// Submit response to a question
   107→router.post('/:id/respond', authMiddleware, async (req, res) => {
   108→  try {
   109→    const { question_index, response_text, video_url } = req.body;
   110→
   111→    // Get interview
   112→    const interview = await pool.query(
   113→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
   114→      [req.params.id, req.user.id]
   115→    );
   116→
   117→    if (interview.rows.length === 0) {
   118→      return res.status(404).json({ error: 'Interview not found' });
   119→    }
   120→
   121→    const interviewData = interview.rows[0];
   122→    const questions = interviewData.questions;
   123→    const question = questions[question_index];
   124→
   125→    if (!question) {
   126→      return res.status(400).json({ error: 'Invalid question index' });
   127→    }
   128→
   129→    // Analyze response with AI
   130→    const analysis = await analyzeInterviewResponse(
   131→      question.question,
   132→      response_text,
   133→      question.key_points || [],
   134→      { subscriptionId: req.user.stripe_subscription_id }
   135→    );
   136→
   137→    // Update responses array
   138→    const responses = interviewData.responses || [];
   139→    responses[question_index] = {
   140→      question_index,
   141→      response_text,
   142→      video_url,
   143→      analysis,
   144→      submitted_at: new Date().toISOString()
   145→    };
   146→
   147→    // Update video URLs if provided
   148→    const videoUrls = interviewData.video_urls || [];
   149→    if (video_url) {
   150→      videoUrls[question_index] = video_url;
   151→    }
   152→
   153→    // Update responses - use updated_at if column exists, fallback gracefully
   154→    try {
   155→      await pool.query(
   156→        `UPDATE interviews SET responses = $1, video_urls = $2, updated_at = NOW()
   157→         WHERE id = $3`,
   158→        [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   159→      );
   160→    } catch (updateErr) {
   161→      // Fallback if updated_at column doesn't exist yet (pre-migration)
   162→      if (updateErr.message && updateErr.message.includes('updated_at')) {
   163→        console.warn('updated_at column missing, updating without it');
   164→        await pool.query(
   165→          `UPDATE interviews SET responses = $1, video_urls = $2
   166→           WHERE id = $3`,
   167→          [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   168→        );
   169→      } else {
   170→        throw updateErr;
   171→      }
   172→    }
   173→
   174→    res.json({
   175→      success: true,
   176→      analysis,
   177→      questions_remaining: questions.length - responses.filter(r => r).length
   178→    });
   179→  } catch (err) {
   180→    console.error('Submit response error:', err);
   181→    res.status(500).json({ error: 'Failed to submit response' });
   182→  }
   183→});
   184→
   185→// Complete interview and get overall feedback
   186→router.post('/:id/complete', authMiddleware, async (req, res) => {
   187→  try {
   188→    const interview = await pool.query(
   189→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
   190→      [req.params.id, req.user.id]
   191→    );
   192→
   193→    if (interview.rows.length === 0) {
   194→      return res.status(404).json({ error: 'Interview not found' });
   195→    }
   196→
   197→    const interviewData = interview.rows[0];
   198→    const responses = interviewData.responses || [];
   199→    const validResponses = responses.filter(r => r && r.analysis);
   200→
   201→    if (validResponses.length === 0) {
   202→      return res.status(400).json({ error: 'No responses to evaluate' });
   203→    }
   204→
   205→    // Generate overall feedback
   206→    const overallFeedback = await generateOverallFeedback(
   207→      validResponses.map(r => r.analysis),
   208→      { subscriptionId: req.user.stripe_subscription_id }
   209→    );
   210→
   211→    // Calculate duration
   212→    const startTime = new Date(interviewData.created_at);
   213→    const duration = Math.floor((Date.now() - startTime.getTime()) / 1000);
   214→
   215→    // Update interview record
   216→    await pool.query(
   217→      `UPDATE interviews SET
   218→        status = 'completed',
   219→        ai_feedback = $1,
   220→        overall_score = $2,
   221→        duration_seconds = $3,
   222→        completed_at = NOW()
   223→       WHERE id = $4`,
   224→      [JSON.stringify(overallFeedback), overallFeedback.overall_score, duration, req.params.id]
   225→    );
   226→
   227→    // Update OmniScore with interview results
   228→    let omniscoreUpdate = null;
   229→    try {
   230→      omniscoreUpdate = await omniscoreService.addInterviewComponent(
   231→        req.user.id,
   232→        req.params.id,
   233→        overallFeedback.overall_score
   234→      );
   235→
   236→      // Update role-specific score if job title is available
   237→      if (interviewData.job_id) {
   238→        const job = await pool.query('SELECT title FROM jobs WHERE id = $1', [interviewData.job_id]);
   239→        if (job.rows.length > 0) {
   240→          await omniscoreService.updateRoleScore(
   241→            req.user.id,
   242→            job.rows[0].title,
   243→            overallFeedback.overall_score
   244→          );
   245→        }
   246→      }
   247→    } catch (scoreErr) {
   248→      console.error('OmniScore update error:', scoreErr);
   249→      // Don't fail the request if OmniScore update fails
   250→    }
   251→
   252→    res.json({
   253→      success: true,
   254→      overall_feedback: overallFeedback,
   255→      duration_seconds: duration,
   256→      response_count: validResponses.length,
   257→      omniscore: omniscoreUpdate
   258→    });
   259→  } catch (err) {
   260→    console.error('Complete interview error:', err);
   261→    res.status(500).json({ error: 'Failed to complete interview' });
   262→  }
   263→});
   264→
   265→// Get interview history
   266→router.get('/history', authMiddleware, async (req, res) => {
   267→  try {
   268→    const { limit = 10, offset = 0 } = req.query;
   269→
   270→    const result = await pool.query(
   271→      `SELECT i.*, j.title as job_title, j.company as job_company
   272→       FROM interviews i
   273→       LEFT JOIN jobs j ON i.job_id = j.id
   274→       WHERE i.user_id = $1
   275→       ORDER BY i.created_at DESC
   276→       LIMIT $2 OFFSET $3`,
   277→      [req.user.id, limit, offset]
   278→    );
   279→
   280→    res.json({ interviews: result.rows });
   281→  } catch (err) {
   282→    console.error('Get history error:', err);
   283→    res.status(500).json({ error: 'Failed to fetch history' });
   284→  }
   285→});
   286→
   287→// Get interview details
   288→router.get('/:id', authMiddleware, async (req, res) => {
   289→  try {
   290→    const result = await pool.query(
   291→      `SELECT i.*, j.title as job_title, j.company as job_company
   292→       FROM interviews i
   293→       LEFT JOIN jobs j ON i.job_id = j.id
   294→       WHERE i.id = $1 AND i.user_id = $2`,
   295→      [req.params.id, req.user.id]
   296→    );
   297→
   298→    if (result.rows.length === 0) {
   299→      return res.status(404).json({ error: 'Interview not found' });
   300→    }
   301→
   302→    res.json({ interview: result.rows[0] });
   303→  } catch (err) {
   304→    console.error('Get interview error:', err);
   305→    res.status(500).json({ error: 'Failed to fetch interview' });
   306→  }
   307→});
   308→
   309→// Upload video for interview response
   310→router.post('/upload-video', authMiddleware, upload.single('video'), async (req, res) => {
   311→  try {
   312→    if (!req.file) {
   313→      return res.status(400).json({ error: 'No video file provided' });
   314→    }
   315→
   316→    const { interview_id, question_index } = req.body;
   317→
   318→    if (!interview_id || question_index === undefined) {
   319→      return res.status(400).json({ error: 'Missing interview_id or question_index' });
   320→    }
   321→
   322→    // Verify interview belongs to user
   323→    const interview = await pool.query(
   324→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
   325→      [interview_id, req.user.id]
   326→    );
   327→
   328→    if (interview.rows.length === 0) {
   329→      return res.status(404).json({ error: 'Interview not found' });
   330→    }
   331→
   332→    // Upload to R2
   333→    const formData = new FormData();
   334→    formData.append('file', req.file.buffer, {
   335→      filename: `interview-${interview_id}-q${question_index}.webm`,
   336→      contentType: req.file.mimetype
   337→    });
   338→
   339→    const uploadRes = await fetch('https://polsia.com/api/proxy/r2/upload', {
   340→      method: 'POST',
   341→      headers: {
   342→        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
   343→        ...formData.getHeaders()
   344→      },
   345→      body: formData
   346→    });
   347→
   348→    const result = await uploadRes.json();
   349→
   350→    if (!result.success) {
   351→      console.error('R2 upload error:', result.error);
   352→      return res.status(500).json({ error: 'Failed to upload video' });
   353→    }
   354→
   355→    res.json({
   356→      success: true,
   357→      video_url: result.file.url
   358→    });
   359→  } catch (err) {
   360→    console.error('Upload video error:', err);
   361→    res.status(500).json({ error: 'Failed to upload video' });
   362→  }
   363→});
   364→
   365→// Get stats for dashboard
   366→router.get('/stats/summary', authMiddleware, async (req, res) => {
   367→  try {
   368→    const stats = await pool.query(
   369→      `SELECT
   370→        COUNT(*) as total_interviews,
   371→        COUNT(CASE WHEN status = 'completed' THEN 1 END) as completed,
   372→        AVG(CASE WHEN overall_score IS NOT NULL THEN overall_score END) as avg_score,
   373→        MAX(overall_score) as best_score
   374→       FROM interviews
   375→       WHERE user_id = $1`,
   376→      [req.user.id]
   377→    );
   378→
   379→    const recentScores = await pool.query(
   380→      `SELECT overall_score, created_at
   381→       FROM interviews
   382→       WHERE user_id = $1 AND status = 'completed' AND overall_score IS NOT NULL
   383→       ORDER BY created_at DESC
   384→       LIMIT 10`,
   385→      [req.user.id]
   386→    );
   387→
   388→    res.json({
   389→      stats: stats.rows[0],
   390→      recent_scores: recentScores.rows
   391→    });
   392→  } catch (err) {
   393→    console.error('Get stats error:', err);
   394→    res.status(500).json({ error: 'Failed to fetch stats' });
   395→  }
   396→});
   397→
   398→// =============== INTERVIEW PRACTICE & COACHING ===============
   399→
   400→// Predefined question library (shared between routes)
   401→const PRACTICE_QUESTION_LIBRARY = [
   402→      // Behavioral Questions
   403→      {
   404→        id: 'beh-1',
