   406→        difficulty: 'Medium',
   407→        question: 'Tell me about a time when you had to deal with a difficult team member. How did you handle it?',
   408→        key_points: ['Conflict resolution', 'Communication skills', 'Team dynamics', 'Professional approach']
   409→      },
