   731→    // Switch practice mode
   732→    function switchPracticeMode(mode) {
   733→      practiceMode = mode;
   734→
   735→      // Update toggle buttons
   736→      document.querySelectorAll('.mode-btn').forEach(btn => {
   737→        btn.classList.remove('active');
   738→        if (btn.dataset.mode === mode) {
   739→          btn.classList.add('active');
   740→        }
   741→      });
   742→
   743→      // Show/hide appropriate areas
   744→      if (mode === 'text') {
   745→        document.getElementById('text-response-area').style.display = 'block';
   746→        document.getElementById('video-response-area').classList.remove('active');
   747→        document.getElementById('video-text-response-area').style.display = 'none';
   748→
   749→        // Stop video if running
   750→        if (videoStream) {
   751→          videoStream.getTracks().forEach(track => track.stop());
   752→          videoStream = null;
   753→        }
   754→      } else {
   755→        document.getElementById('text-response-area').style.display = 'none';
   756→        document.getElementById('video-response-area').classList.add('active');
   757→      }
   758→    }
