   760→    // Start video practice - camera init is DECOUPLED from VideoAnalyzer
   761→    async function startVideoPractice() {
   762→      const startBtn = document.getElementById('start-video-btn');
   763→      startBtn.textContent = '⏳ Starting camera...';
   764→      startBtn.disabled = true;
   765→
   766→      try {
   767→        // Step 1: Get camera/mic stream (this is the critical part)
   768→        videoStream = await navigator.mediaDevices.getUserMedia({
   769→          video: { width: { ideal: 1280 }, height: { ideal: 720 } },
   770→          audio: {
   771→            echoCancellation: true,
   772→            noiseSuppression: true,
   773→            autoGainControl: true
   774→          }
   775→        });
   776→
   777→        // Step 2: Attach stream to video element
   778→        const videoEl = document.getElementById('practice-video');
   779→        videoEl.srcObject = videoStream;
   780→        await videoEl.play().catch(() => {}); // ensure playback starts
   781→
   782→        // Step 3: Update UI - camera is working, show record button
   783→        startBtn.style.display = 'none';
   784→        document.getElementById('record-video-btn').style.display = 'inline-flex';
   785→
   786→        // Verify audio tracks
   787→        const audioTracks = videoStream.getAudioTracks();
   788→        if (audioTracks.length === 0) {
